// Generated by AI Assistant

import { render, screen } from '@testing-library/react';
import React from 'react';

import { AiSelectorErrorBoundary } from '@/components/AiSelector/ErrorBoundary';

function ProblemChild(): React.ReactElement {
  throw new Error('test error');
}

describe('AiSelectorErrorBoundary', () => {
  beforeEach(() => {
    jest.spyOn(console, 'error').mockImplementation(() => {});
  });

  afterEach(() => {
    jest.restoreAllMocks();
  });

  it('should render children when no error', () => {
    render(
      <AiSelectorErrorBoundary>
        <span>child content</span>
      </AiSelectorErrorBoundary>,
    );

    expect(screen.getByText('child content')).toBeDefined();
  });

  it('should render error alert when child throws', () => {
    render(
      <AiSelectorErrorBoundary>
        <ProblemChild />
      </AiSelectorErrorBoundary>,
    );

    expect(screen.getByText('AI Provider Selector unavailable')).toBeDefined();
    expect(screen.getByText(/The AI provider selector failed to load/)).toBeDefined();
  });
});
